import React, { useEffect, useRef } from 'react';
import './LightPillar.css';

const LightPillar = ({
  topColor = '#912bb6',
  bottomColor = '#8f14c8',
  intensity = 1.5,
  rotationSpeed = 0.3,
  interactive = false,
  glowAmount = 0.002,
  pillarWidth = 7.5,
  pillarHeight = 0.75,
  noiseIntensity = 1.9,
  pillarRotation = 270,
}) => {
  const containerRef = useRef(null);
  const canvasRef = useRef(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext('2d');
    let animationId;
    let rotation = pillarRotation;

    // Set canvas size
    const container = containerRef.current;
    canvas.width = container.clientWidth;
    canvas.height = container.clientHeight;

    const centerX = canvas.width / 2;
    const centerY = canvas.height / 2;

    const animate = () => {
      // Clear canvas with slight trail effect
      ctx.fillStyle = 'rgba(0, 0, 0, 0.02)';
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      // Update rotation
      rotation += rotationSpeed;

      // Draw multiple pillars
      for (let i = 0; i < 3; i++) {
        const angle = (rotation + i * 120) * (Math.PI / 180);
        drawPillar(
          ctx,
          centerX,
          centerY,
          angle,
          topColor,
          bottomColor,
          pillarWidth,
          pillarHeight,
          intensity,
          glowAmount
        );
      }

      animationId = requestAnimationFrame(animate);
    };

    const drawPillar = (
      ctx,
      x,
      y,
      angle,
      topColor,
      bottomColor,
      width,
      height,
      intensity,
      glowAmount
    ) => {
      ctx.save();
      ctx.translate(x, y);
      ctx.rotate(angle);

      // Draw gradient pillar
      const gradient = ctx.createLinearGradient(0, -300, 0, 300);
      gradient.addColorStop(0, topColor);
      gradient.addColorStop(0.5, bottomColor);
      gradient.addColorStop(1, topColor);

      ctx.fillStyle = gradient;
      ctx.fillRect(-width / 2, -300, width, 600);

      // Add glow effect
      ctx.globalAlpha = glowAmount * intensity;
      ctx.fillStyle = topColor;
      ctx.shadowColor = topColor;
      ctx.shadowBlur = 50 * intensity;
      ctx.fillRect(-width / 2, -300, width, 600);

      ctx.restore();
    };

    animate();

    return () => cancelAnimationFrame(animationId);
  }, [topColor, bottomColor, intensity, rotationSpeed, glowAmount, pillarWidth, pillarHeight, pillarRotation]);

  return (
    <div ref={containerRef} className="light-pillar-container">
      <canvas
        ref={canvasRef}
        className="light-pillar-canvas"
        style={{
          display: 'block',
          width: '100%',
          height: '100%',
        }}
      />
    </div>
  );
};

export default LightPillar;
